#[derive(Clone, Default, serde::Serialize, serde::Deserialize)]
pub struct PreprocessingOptions {
    /// Enable HTML preprocessing globally
    pub enabled: bool,
    /// Preprocessing preset level (Minimal, Standard, Aggressive)
    pub preset: PreprocessingPreset,
    /// Remove navigation elements (nav, breadcrumbs, menus, sidebars)
    pub remove_navigation: bool,
    /// Remove form elements (forms, inputs, buttons, etc.)
    pub remove_forms: bool,
}

impl PreprocessingOptions {
    #[must_use]

    pub fn new(
        enabled: Option<bool>,
        preset: Option<PreprocessingPreset>,
        remove_navigation: Option<bool>,
        remove_forms: Option<bool>,
    ) -> Self {
        Self {
            enabled: enabled.unwrap_or(true),
            preset: preset.unwrap_or_default(),
            remove_navigation: remove_navigation.unwrap_or(true),
            remove_forms: remove_forms.unwrap_or(true),
        }
    }

    pub fn apply_update(&self, update: PreprocessingOptionsUpdate) -> Self {
        let update_core: html_to_markdown_rs::PreprocessingOptionsUpdate = update.into();
        let mut core_self = html_to_markdown_rs::options::PreprocessingOptions {
            enabled: self.enabled,
            preset: self.preset.clone().into(),
            remove_navigation: self.remove_navigation,
            remove_forms: self.remove_forms,
        };
        core_self.apply_update(update_core);
        core_self.into()
    }

    #[allow(clippy::should_implement_trait)]
    pub fn default() -> PreprocessingOptions {
        html_to_markdown_rs::options::PreprocessingOptions::default().into()
    }

    pub fn from_update(update: PreprocessingOptionsUpdate) -> PreprocessingOptions {
        let update_core: html_to_markdown_rs::PreprocessingOptionsUpdate = update.into();
        html_to_markdown_rs::options::PreprocessingOptions::from_update(update_core).into()
    }

    #[allow(clippy::should_implement_trait)]
    pub fn from(update: PreprocessingOptionsUpdate) -> PreprocessingOptions {
        let update_core: html_to_markdown_rs::PreprocessingOptionsUpdate = update.into();
        html_to_markdown_rs::options::PreprocessingOptions::from(update_core).into()
    }
}

#[extendr]
pub fn new_preprocessingoptions(
    enabled: Option<bool>,
    preset: Option<PreprocessingPreset>,
    remove_navigation: Option<bool>,
    remove_forms: Option<bool>,
) -> PreprocessingOptions {
    let mut __out = <PreprocessingOptions>::default();
    if let Some(v) = enabled {
        __out.enabled = v;
    }
    if let Some(v) = preset {
        __out.preset = v;
    }
    if let Some(v) = remove_navigation {
        __out.remove_navigation = v;
    }
    if let Some(v) = remove_forms {
        __out.remove_forms = v;
    }
    __out
}

