pub fn new_tablegrid(rows: Option<i32>, cols: Option<i32>, cells: Option<Vec<GridCell>>) -> TableGrid {
    let mut __out = <TableGrid>::default();
    if let Some(v) = rows {
        __out.rows = v;
    }
    if let Some(v) = cols {
        __out.cols = v;
    }
    if let Some(v) = cells {
        __out.cells = v;
    }
    __out
}

