impl From<html_to_markdown_rs::VisitResult> for VisitResult {
    fn from(val: html_to_markdown_rs::VisitResult) -> Self {
        match val {
            html_to_markdown_rs::VisitResult::Continue => Self::Continue,
            html_to_markdown_rs::VisitResult::Custom(..) => Self::Custom,
            html_to_markdown_rs::VisitResult::Skip => Self::Skip,
            html_to_markdown_rs::VisitResult::PreserveHtml => Self::PreserveHtml,
            html_to_markdown_rs::VisitResult::Error(..) => Self::Error,
        }
    }
}

#[allow(clippy::missing_errors_doc)]
#[extendr]
pub fn convert(html: String, options: Option<ConversionOptions>) -> Result<ConversionResult> {
    let options_core: Option<html_to_markdown_rs::ConversionOptions> = options.map(Into::into);
    html_to_markdown_rs::convert(&html, options_core)
        .map(Into::into)
        .map_err(|e| e.to_string())
}

fn nodecontext_to_robj(ctx: &html_to_markdown_rs::visitor::NodeContext) -> extendr_api::Robj {
    use extendr_api::prelude::*;
    let attrs: extendr_api::Robj = ctx
        .attributes
        .iter()
        .map(|(k, v)| (k.as_str(), extendr_api::Robj::from(v.as_str())))
        .collect::<List>()
        .into();
    list!(
        node_type = format!("{:?}", ctx.node_type),
        tag_name = ctx.tag_name.as_str(),
        depth = ctx.depth as i32,
        index_in_parent = ctx.index_in_parent as i32,
        is_inline = ctx.is_inline,
        parent_tag = ctx.parent_tag.as_deref().unwrap_or(""),
        attributes = attrs,
    )
    .into()
}

